 namespace WPAICG\Chat\Utils; if (!defined('ABSPATH')) { exit; } class LogConfig { public static function get_retention_periods(): array { return [ 1 => __('1 Day', 'gpt3-ai-content-generator'), 3 => __('3 Days', 'gpt3-ai-content-generator'), 7 => __('7 Days', 'gpt3-ai-content-generator'), 15 => __('15 Days', 'gpt3-ai-content-generator'), 30 => __('30 Days', 'gpt3-ai-content-generator'), 60 => __('60 Days', 'gpt3-ai-content-generator'), 90 => __('90 Days', 'gpt3-ai-content-generator'), 180 => __('6 Months', 'gpt3-ai-content-generator'), 365 => __('1 Year', 'gpt3-ai-content-generator') ]; } public static function get_valid_periods(): array { return array_keys(self::get_retention_periods()); } public static function is_valid_period($period): bool { if (!is_numeric($period)) { return false; } $numericPeriod = (float) $period; if ($numericPeriod < 1 || $numericPeriod > 365) { return false; } return true; } public static function get_default_settings(): array { return [ 'enable_pruning' => false, 'retention_period_days' => 90 ]; } public static function get_log_settings(): array { $settings = get_option('aipkit_log_settings', self::get_default_settings()); return [ 'enable_pruning' => (bool)($settings['enable_pruning'] ?? false), 'retention_period_days' => (float)($settings['retention_period_days'] ?? 90) ]; } } 